// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Regenerate the static arrival PIN for this location
	// (POST /admin/locations/{location_id}/arrival-pin/regenerate)
	RegenerateArrivalPin(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// List all services (full management view)
	// (GET /admin/locations/{location_id}/services)
	GetAdminLocationsLocationIdServices(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// Create a new service variant
	// (POST /admin/locations/{location_id}/services)
	CreateServiceVariant(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// Update a service variant
	// (PATCH /admin/locations/{location_id}/services/{variant_id})
	UpdateServiceVariant(w http.ResponseWriter, r *http.Request, locationId UUIDv7, variantId UUIDv7)
	// Connect a shop's own WABA (Mode B onboarding)
	// (POST /admin/locations/{location_id}/whatsapp/connect)
	ConnectWhatsAppModeB(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// Disconnect a shop's own WABA (revert to shared platform number)
	// (POST /admin/locations/{location_id}/whatsapp/disconnect)
	DisconnectWhatsAppModeB(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// Add a new staff member
	// (POST /admin/staff)
	CreateStaffMember(w http.ResponseWriter, r *http.Request)
	// [TOOL] Book appointment on behalf of customer
	// (POST /agent/appointments/book)
	AgentBookAppointment(w http.ResponseWriter, r *http.Request)
	// [TOOL] Cancel customer's queue entry
	// (POST /agent/customer/cancel)
	AgentCancelEntry(w http.ResponseWriter, r *http.Request)
	// [TOOL] Get customer's current queue or appointment status
	// (GET /agent/customer/status)
	AgentGetCustomerStatus(w http.ResponseWriter, r *http.Request, params AgentGetCustomerStatusParams)
	// [TOOL] Get shop info and live queue status
	// (GET /agent/locations/{location_id}/info)
	AgentGetShopInfo(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// [TOOL] Join queue on behalf of customer
	// (POST /agent/queue/join)
	AgentJoinQueue(w http.ResponseWriter, r *http.Request)
	// Book an appointment
	// (POST /appointments/book)
	BookAppointment(w http.ResponseWriter, r *http.Request)
	// Refresh access token using httpOnly refresh cookie
	// (POST /auth/staff/refresh)
	RefreshStaffToken(w http.ResponseWriter, r *http.Request)
	// Request WhatsApp OTP for staff login
	// (POST /auth/staff/request-otp)
	RequestStaffOTP(w http.ResponseWriter, r *http.Request)
	// Verify OTP and issue staff JWT
	// (POST /auth/staff/verify-otp)
	VerifyStaffOTP(w http.ResponseWriter, r *http.Request)
	// Get available appointment time slots for a date
	// (GET /public/locations/{location_id}/appointment-slots)
	GetAppointmentSlots(w http.ResponseWriter, r *http.Request, locationId UUIDv7, params GetAppointmentSlotsParams)
	// Resolve allowed entry methods for selected services
	// (POST /public/locations/{location_id}/booking-options)
	ResolveBookingOptions(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// Create a check-in intent for the WhatsApp JOIN handshake
	// (POST /public/locations/{location_id}/checkin-intents)
	CreateCheckinIntent(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
	// Get full hierarchical service catalog
	// (GET /public/locations/{location_id}/service-catalog)
	GetServiceCatalog(w http.ResponseWriter, r *http.Request, locationId UUIDv7, params GetServiceCatalogParams)
	// Search service variants by name
	// (GET /public/locations/{location_id}/service-catalog/search)
	SearchServiceVariants(w http.ResponseWriter, r *http.Request, locationId UUIDv7, params SearchServiceVariantsParams)
	// Get live shop status and queue length
	// (GET /public/locations/{location_slug}/status)
	GetLocationStatus(w http.ResponseWriter, r *http.Request, locationSlug string)
	// Customer cancels their own queue entry
	// (POST /queue/cancel)
	CancelMyEntry(w http.ResponseWriter, r *http.Request)
	// Confirm physical arrival at the shop
	// (POST /queue/confirm-arrival)
	ConfirmArrival(w http.ResponseWriter, r *http.Request)
	// Submit post-service feedback
	// (POST /queue/feedback)
	SubmitFeedback(w http.ResponseWriter, r *http.Request)
	// Join the queue (walk-in)
	// (POST /queue/join)
	JoinQueue(w http.ResponseWriter, r *http.Request)
	// Get customer's live queue status
	// (GET /queue/my-status)
	GetMyQueueStatus(w http.ResponseWriter, r *http.Request)
	// Customer confirms they are heading to the shop
	// (POST /queue/on-the-way)
	ConfirmOnTheWay(w http.ResponseWriter, r *http.Request)
	// Daily revenue and visit summary
	// (GET /staff/analytics/daily)
	GetDailyAnalytics(w http.ResponseWriter, r *http.Request, params GetDailyAnalyticsParams)
	// List staff members for this location
	// (GET /staff/members)
	GetStaffMembers(w http.ResponseWriter, r *http.Request)
	// Update barber operational status
	// (PATCH /staff/members/{staff_id}/status)
	UpdateBarberStatus(w http.ResponseWriter, r *http.Request, staffId UUIDv7)
	// Advance the queue from a lock-screen notification action
	// (POST /staff/push/call-next)
	PushCallNext(w http.ResponseWriter, r *http.Request)
	// Register or update a Web Push subscription for this staff member
	// (POST /staff/push/subscribe)
	SubscribePush(w http.ResponseWriter, r *http.Request)
	// Staff manually adds a walk-in customer
	// (POST /staff/queue/add-walkin)
	AddWalkIn(w http.ResponseWriter, r *http.Request)
	// Call next dispatchable customer
	// (POST /staff/queue/call-next)
	CallNextCustomer(w http.ResponseWriter, r *http.Request)
	// Complete service and checkout (atomic)
	// (POST /staff/queue/entries/{entry_id}/complete)
	CompleteService(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Staff confirms customer arrival (bypasses PIN)
	// (POST /staff/queue/entries/{entry_id}/confirm-arrival)
	StaffConfirmArrival(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Mark customer as no-show (was called, confirmed absent)
	// (POST /staff/queue/entries/{entry_id}/no-show)
	MarkNoShow(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Reactivate a snoozed or skipped customer
	// (POST /staff/queue/entries/{entry_id}/reactivate)
	ReactivateEntry(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Reassign entry to a different barber
	// (POST /staff/queue/entries/{entry_id}/reassign)
	ReassignBarber(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Skip a customer (was called, not present)
	// (POST /staff/queue/entries/{entry_id}/skip)
	SkipEntry(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Start service (called → in_progress)
	// (POST /staff/queue/entries/{entry_id}/start)
	StartService(w http.ResponseWriter, r *http.Request, entryId UUIDv7)
	// Get full queue snapshot for staff dashboard
	// (GET /staff/queue/snapshot)
	GetQueueSnapshot(w http.ResponseWriter, r *http.Request)
	// Get current shop operational status
	// (GET /staff/shop/status)
	GetStaffShopStatus(w http.ResponseWriter, r *http.Request)
	// Change shop status (manual override)
	// (PATCH /staff/shop/status)
	SetShopStatus(w http.ResponseWriter, r *http.Request)
	// SSE stream for queue version pings
	// (GET /stream/{location_id})
	SubscribeToQueueStream(w http.ResponseWriter, r *http.Request, locationId UUIDv7, params SubscribeToQueueStreamParams)
	// Receive normalized WhatsApp event from Bhejna
	// (POST /webhooks/bhejna)
	ReceiveBhejnaWebhook(w http.ResponseWriter, r *http.Request)
	// Bhejna inbound webhook (Mode B — per-location)
	// (POST /webhooks/bhejna/loc/{location_id})
	ReceiveBhejnaWebhookModeB(w http.ResponseWriter, r *http.Request, locationId UUIDv7)
}

